var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，得到回應說他馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"으음~ 좋군요. 등골을 타고 머리로 치닫는 이 오싹한 감각......","JPN":"う～ん、良いですねぇ。この背筋から頭のてっぺんまで、ゾクゾクする感覚……","ENG":"Mmm, nice. I feel a shiver running down my spine.","TWN":"嗯～真棒呢。這種從背脊衝上腦門的顫慄感……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"정말 오랜만에 느껴 봅니다. 제가 진정으로 존경하는 분에게 신뢰 받는다는 기분 말이죠.","JPN":"こんな気分は実に久しぶりです。心から尊敬する相手から信頼を受けるというのは、何とも言えない心地ですねぇ。","ENG":"It's been a while since I last felt this excitement of being trusted by the person I admire from the bottom of my heart.","TWN":"真是好久沒體驗到了，這就是被自己尊敬的人信賴的感覺啊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"저는 지금껏 각본대로만 살아왔다고 해도 무방합니다.","JPN":"今までの私は、筋書き通りにしか生きていなかったと言っても過言ではありません。","ENG":"It wouldn't be too much to say that my life, until now, has been scripted all along.","TWN":"說我一直以來，都是按照劇本活過來的也無所謂。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"제가 각본을 어긴 채 본심이 이끄는 대로만 행동한다면, 저희 주인님이 별로 좋아하시지 않을 테니까 말이죠.","JPN":"私がその筋書きを破り、本心に従って行動してしまったら、我が主はあまり喜ばれないでしょうからね。","ENG":"I knew that my Mistress wouldn't like it if I did what my heart wanted, not what I was told.","TWN":"要是我違背劇本，遵從自己內心來行動的話，我們的主人大人會不太歡喜吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그래서 저는 가면을 눌러쓴 채 비극처럼 거짓된 삶을 살아왔답니다.","JPN":"だから私は仮面を深く被り、悲劇じみた偽りの生涯を送ってきました。","ENG":"So I put on a mask and lived a lie, like a hero in a tragedy.","TWN":"所以我一直戴著面具，過著悲劇一般的虛偽人生。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"하지만 당신은 달라요. 제 본성을 꿰뚫어보셨고, 그럼에도 이 자리까지 저를 초대해주셨죠.","JPN":"でもあなたは違います。私の本性を見抜いておられる。その上で、この場に招いてくださったのです。","ENG":"But you were different. You saw right through me, but still invited me anyway.","TWN":"但您不同。就算看穿了了我的本性，您仍邀請了我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"정말이지 흥분됩니다. 이렇게 스스럼없이 비밀을 나눌 수 있는 상대가 제 앞에 있다니......","JPN":"興奮が抑えきれませんねぇ。こうして包み隠さず秘密を話し合える相手が、我が目の前にいようとは……","ENG":"You have no idea what kind of feelings it provokes in me. How amazing is it that I'm standing in front of the person I can share my secrets with!","TWN":"真令人興奮啊。我眼前竟然有個能夠敞開心房，傾訴秘密的對象……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"하아...... 이 오싹한 전율! 도저히 멈출 수가 없어요!","JPN":"ふうぅ……このゾクゾクする戦慄！とても抑えきれません！","ENG":"*Huff* Ah, there it goes again! The thrill! I can't stop it!","TWN":"哈啊……啊，這個發寒的戰慄！根本停不下來！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"아니, 멈추고 싶지 않습니다! 가능하다면 여운의 여운까지도 집요하게 만끽하고 싶어지는군요!","JPN":"いいえ、抑えたくないのです！できることなら余韻の余韻まで、とことんしゃぶり尽くしたいほどです！","ENG":"No, I don't want it to stop! I'd like to enjoy this feeling to the very last bit if I can.","TWN":"不，我不想停下來！可以的話，我就連這餘韻的餘韻都要盡情地享受！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"하지만 지나친 탐닉은 역시, 풍미를 떨어뜨리는 행위겠지요.","JPN":"しかしながら、あまり満喫してしまうのも、風味を損ないかねない行為のはずです。","ENG":"But overindulgence kills the savor fast.","TWN":"但是過度的貪婪果然，是種糟蹋風味的行為吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"고통도 쾌감도...... 그리고 귀한 포도주처럼 천천히 음미해야 한다는 것이 제 지론입니다.","JPN":"苦痛も、快感も……年代物のワインと同じように、ゆっくりと味わうべきというのが私の持論です。","ENG":"Pleasure, just like pain, is best appreciated slow and easy, like fine wine.","TWN":"無論是痛覺還是快感……都要當作名貴的紅酒般，細細地品味，這才是我的主張。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"과연 독특하십니다. 저와 잠시 인연이 닿았던 분들께선 이쯤이면 대개 질색하시거나 그런 기색을 숨기려고 고생하시던데......","JPN":"さすがは独特な風味をお持ちですね。私と少しでも触れ合った者は、すぐに嫌気を起こすか、それを必死に隠そうとするかのどちらかでしたが……","ENG":"You're quite peculiar. Whenever I acted like this, those who tried to keep company with me were usually overwhelmed with contempt, not knowing whether to blame or ignore me.","TWN":"您果然很特別呢。和我有緣相會的人們在這時候，通常都會感到厭惡，或是極力掩飾自己的反感……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"사장님께선 달리 개의치 않으시는군요. 마치 저의 비밀은 당신의 것에 비하면 아무 것도 아니라는 것처럼.","JPN":"社長はあまり気にされていないように見えます。まるで……私の秘密はあなたのそれに比べれば何でもないといったふうに。","ENG":"None of them were as genuinely indifferent as you are. It's as if my secrets are nothing compared to yours.","TWN":"但老闆您完全不一樣呢。就好像我的秘密和您的秘密比起來，根本算不上什麼。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후. 정말 이 인연이 다시 한 번 각별해지는군요.","JPN":"フフ、この縁は実に格別ですね。ますます味わい深くなってきましたよ。","ENG":"Hah hah. The more I think about this relationship, the more I cherish it.","TWN":"呵呵，這讓我們的緣分又變得更特別了一點。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"다음 번엔, 서로의 비밀을 더 깊이 캐나가는 시간을 갖도록 합시다.","JPN":"今度は、お互いの秘密をより深く掘り下げる時を持つとしましょう。","ENG":"We should really meet up some time and dig into each other's secrets.","TWN":"下次，就讓我們能有段時間，來挖掘對方更深層的秘密吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};